document.getElementById("Alternate5040_base_change").addEventListener("change", function() {
    try {
        v = BigInt(this.value);
        if (v <= 1n) throw new Error();
    }
    catch {
        if (mode_vars[0] == 4 || mode_vars[0] == 8) {
            v = new BigRational(this.value);
            console.log(this.value);
            console.log(v);
            if (v.lt(0)) v = v.abs();
            if (v.lt(1)) v = v.recip();
            if (v.gt(1) && v.isFinite()) {
                mode_vars[1] = v;
                secretsFound[2] = true;
            }
            loadGridSize(100, mode_vars);
            gmDisplayVars();
            return;
        }
        else v = 0n;
    }
    if (v > 1n) mode_vars[1] = v;
    loadGridSize(100, mode_vars);
    gmDisplayVars();
});
