document.getElementById("Alternate5040_baseListRandomize_button").addEventListener("click", function(){
    let amount = 2;
    let mult = 1;
    let power = typeof mode_vars[1] == "bigint";
    let power2 = mode_vars[1] instanceof BigRational;
    if(power || power2) mult = 1.6;
    mode_vars[1] = [];
    for(let i = 0; i < 10; i++) {
        if(Math.random() < 0.25) amount++;
    }
    for(let i = 0; i < amount; i++) {
        let randomNum = 1;
        for(let j = 0; j < 6; j++) {
            randomNum *= 1 + mult * Math.random();
        }
        mode_vars[1].push(BigInt(Math.ceil(randomNum)));
    }
    if(power) mode_vars[1] = mode_vars[1][0];
    if (power2) {
        mode_vars[1] = new BigRational(mode_vars[1][0], mode_vars[1][1]);
        if (mode_vars[1].lt(1)) mode_vars[1] = mode_vars[1].recip();
        if (mode_vars[1].eq(1)) mode_vars[1] = new BigRational(mode_vars[1].numerator)
    }
    loadGridSize(100, mode_vars);
    gmDisplayVars();
});
