document.getElementById("start_game").addEventListener("click", () => { startGame(); });
document.addEventListener("keydown", (event) => {
    if (!inputAvailable || isPlayingReplay || (currentScreen != "Gameplay" && !(currentScreen == "Modifiers" && subScreen == 3.2)) || (currentScreen == "Gameplay" && gameplayComponentOpacities.length > 0 && CalcArray(gameplayComponentOpacities[0]) < 0)) return;
    let directionUsed = -1;
    directionFinder : {
        for (let d = 0; d < directions.length; d++) {
            for (let k = 0; k < directions[d][7].length; k++) {
                if (directions[d][7][k] == event.code) {directionUsed = d; break directionFinder;}
            }
        }
    }
    if (currentScreen == "Gameplay" && directionUsed >= 0 && directionsAvailable[directionUsed] && (CalcArray(directionBlocked, 0, 0, directions[directionUsed][0][0], directions[directionUsed][0][1], [1, directions[directionUsed][0][2], directions[directionUsed][0][3], directionUsed + 1], Grid, [], [directionUsed]) !== true)) MoveHandler(directionUsed);
    if (currentScreen == "Modifiers" && subScreen == 3.2) {
        if (directionUsed == -1) directions[screenVars[0]][7].push(event.code);
        inputAvailable = false;
        displayModifiers(3.2);
    }
});
window.addEventListener("resize", function(){
    if (currentScreen == "Menu") {
        if (subScreen === -2) {
            if ((window.screen.width / window.screen.height) <= 3/4) document.getElementById("menu_extra").innerHTML = "Switch Pages (Infused " + (screenVars[0] + 1) + " / " + infusedGrids.length + ")" 
            else document.getElementById("menu_extra").innerHTML = "Switch Pages<br>(Infused " + (screenVars[0] + 1) + " / " + infusedGrids.length + ")" ; 
        }
        else {
            if ((window.screen.width / window.screen.height) <= 3/4) document.getElementById("menu_extra").innerHTML = "Switch Pages (" + subScreen + " / 4)" 
            else document.getElementById("menu_extra").innerHTML = "Switch Pages<br>(" + subScreen + " / 4)"; 
        }
    }
    if (currentScreen == "Gameplay" && inputAvailable) {
        displayGrid("Resize");
    }
})
