document.getElementById("modifiers_customGridActivate").addEventListener("click", function() {
    modifiers[5] = "Custom";
    if (hexagonal) auto_directions = [];
    hexagonal = false;
    customGridWidth = 4;
    customGridHeight = 4;
    directions = [
        [[-1, 0, modifiers[0], 0, [1, true, true, true]], "↑", 5/33, 5/33, 3/33, 6/33, 14/33, ["ArrowUp", "KeyW"], 0],
        [[1, 0, modifiers[0], 0, [1, true, true, true]], "↓", 5/33, 5/33, 3/33, 22/33, 14/33, ["ArrowDown", "KeyS"], 0],
        [[0, -1, modifiers[0], 0, [1, true, true, true]], "←", 5/33, 5/33, 3/33, 14/33, 6/33, ["ArrowLeft", "KeyA"], 0],
        [[0, 1, modifiers[0], 0, [1, true, true, true]], "→", 5/33, 5/33, 3/33, 14/33, 22/33, ["ArrowRight", "KeyD"], 0],
    ];
    directionsAvailable = [true, true, true, true];
    createCustomGrid();
    switchScreen("Modifiers", 3.1);
});
