let addInfusedGridTile = function(){
    try {
        let code = document.getElementById("infusedGridTextarea").value;
        let sc = compendiumStructuredClone(screenVars);
        if (code.split("|")[0] === "@2048PowCompInfused" || code.split("|")[0] === "@2048PowCompCustom" || code.split("|")[0] === "@2048PowCompMode") {
            importSave(code);
            let result = [code];
            let bigTileElem = document.getElementById("gm_big_tile");
            if (currentScreen != "Gamemode" || getComputedStyle(bigTileElem).getPropertyValue("display") === "none") {
                let headingOrder = ["h1", "h2", "h3", "h4", "h5", "h6", "p", ""];
                let bigTileText = ["", ""];
                let ruleToCheck = (currentScreen != "Gamemode") ? gameplayRulesText : gmRulesText;
                for (let rulesIndex = 0; rulesIndex < ruleToCheck.length; rulesIndex++) {
                    let hoIndex = headingOrder.indexOf(ruleToCheck[rulesIndex][0]);
                    if (hoIndex != -1 && hoIndex < headingOrder.indexOf(bigTileText[0])) bigTileText = compendiumStructuredClone(ruleToCheck[rulesIndex]);
                }
                result.push(bigTileText[1]);
                result.push(Math.min(16, 25 / bigTileText[1].length) / 1.25);
                result.push((currentScreen != "Gamemode") ? evaluateColor(gameplayBackground) : evaluateColor(gmBackground));
            }
            else {
                result.push(document.getElementById("gm_big_tile").innerHTML)
                result.push(getComputedStyle(document.getElementById("gm_big_tile")).getPropertyValue("--gm_tfs") / 1.25)
                let background = getComputedStyle(document.getElementById("gm_big_tile")).getPropertyValue("background-image");
                if (background == "none") background = getComputedStyle(document.getElementById("gm_big_tile")).getPropertyValue("background-color")
                result.push(background)
            }
            infusedGrids[sc[0]][sc[1]] = result;
            switchScreen("CustomMode", "Infused Grid Manager");
            screenVars = sc;
        }
        else throw new Error("Wrong save code type")
    }
    catch (err) {
        document.getElementById("infusedGridTextarea").value = "There was an error with your save code: " + err;
    }
    displayCustomMode("Infused Grid Manager", screenVars);
}
