                if (CalcArray(modifiersList[mindex][7], ...[,,,,,,,], [compendiumStructuredClone(mode_vars), compendiumStructuredClone(modifiers), [compendiumStructuredClone(settingModifiers), compendiumStructuredClone(directions), compendiumStructuredClone(auto_directions)], mode_vars[mindex]]) == false) {
                    document.getElementById("infusedMode_var" + mindex).style.setProperty("display", "none")
                }
